import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder out = new StringBuilder();
        int T = fs.nextInt();
        int printed = 0;
        for (int i = 0; i < T; i++) {
            int choice = fs.nextInt();
            String line = null;
            if (choice == 1) line = "Option 1 selected";
            else if (choice == 2) line = "Option 2 selected";
            else if (choice == 3) line = "Option 3 selected";
            if (line != null) {
                if (printed > 0) out.append('\n');
                out.append(line);
                printed++;
            }
        }
        System.out.print(out.toString());
    }

    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream stream) {
            in = new BufferedInputStream(stream);
        }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do {
                c = readByte();
            } while (c <= ' ' && c != -1);
            if (c == '-') {
                sign = -1;
                c = readByte();
            }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

